UPDATE youtube_comment_analysis_histories
SET
    preprocessed_file_path = #{preprocessedFilePath},
    preprocessed_saved_at = #{preprocessedSavedAt}
WHERE id = #{id}
  AND (#{userId} IS NULL OR user_id = #{userId})

UPDATE youtube_comment_analysis_histories
SET
    analysis_requested_at = #{analysisRequestedAt}
WHERE id = #{id}
  AND (#{userId} IS NULL OR user_id = #{userId})
